import Sidebar from '../components/Sidebar';
import startImage from '../assets/startpage.png';

function MainPage() {
  return (
    <div className="relative w-full min-h-screen bg-white overflow-hidden">
      {/* 흐릿한 배경 이미지 */}
      <img
        src={startImage}
        alt="배경"
        className="absolute top-0 left-0 w-full h-full object-cover opacity-20 blur-2xl -z-10"
      />

      {/* 페이지 레이아웃 */}
      <div className="relative z-10 flex px-8 pt-12 items-start">
        {/* 사이드바 */}
        <Sidebar />

        {/* 오른쪽 메인 콘텐츠 */}
        <main className="flex-1 flex items-center justify-center min-h-[90vh]">
          {/* 중앙 콘텐츠 상자 */}
          <div className="w-[800px] h-[500px] bg-white/70 backdrop-blur-md rounded-xl flex items-center justify-center text-xl font-bold text-gray-800 shadow-lg">
            메인 콘텐츠 영역입니다.
          </div>
        </main>
      </div>
    </div>
  );
}

export default MainPage;
